var e=[{id:`L3_1`,type:`dialog`,speaker:`COUNTER_NPC_M_NULL`,text:{KOREA:`적들의 물량이 너무 많아! 전선을 물려야 해!`,JPN:`敵の数が多すぎる！　前線を後ろに下げるべきだ！`,ENG:`There are too many of them! We have to push back the line!`,TWN:`敵人數量太多！必須從前線撤退！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`GATE_NPC_CHARADE_NULL`,text:{KOREA:`벌써 저지 한계선입니다! 이 뒤는 사람들이 있다고요!`,JPN:`これ以上は無理です！　この後ろには民間人がいます！`,ENG:`This is the limit! There are people behind us!`,TWN:`已經是極限了！不能再退了！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`COUNTER_NPC_M_NULL`,text:{KOREA:`중화기들이 모두 작살났어! 여기서 억지로 버텨봐야 전부 개죽음이야!`,JPN:`重火器がすべて壊された！　ここで無理やり粘っていても、全員無駄死にするだけだ！`,ENG:`All the heavy firearms are broken! We're all going to die for nothing if we don't back up!`,TWN:`所有重型武器都被破壞了！就算硬撐也只有死路一條！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`GATE_NPC_CHARADE_NULL`,text:{KOREA:`바리케이트에 심어 둔 장약을 터트리면 돼요. 시간은 더 벌 수 있을 겁니다.`,JPN:`バリケードに入れておいた装薬を爆破すれば、時間は稼げるはずです。`,ENG:`We can detonate the explosive charge we planted in the barricade. It'll buy us more time.`,TWN:`引爆路障內的火藥就可以再拖延一些時間。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`COUNTER_NPC_M_NULL`,text:{KOREA:`샤레이드에서 이런 장기교전을 할 줄은 몰랐는데…`,JPN:`シャレードでこんなにも長く交戦することになるなんて……`,ENG:`I didn't think I'd end up engaging in a long-term battle like this in Charade...`,TWN:`沒想到會在查雷德進行如此長時間的交戰……`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`COUNTER_NPC_M_NULL`,text:{KOREA:`좋아! 그렇게 말해 놓고 먼저 죽지나 마라!`,JPN:`よし！　そう言っておいて、先に死ぬなよ！`,ENG:`All right! I better not see you dead after saying all that crap!`,TWN:`好！你可別先死掉！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`GATE_NPC_CHARADE_NULL`,text:{KOREA:`제2파! 옵니다!`,JPN:`第2派！　来ます！`,ENG:`The second wave is approaching!`,TWN:`第二波！來了！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`COUNTER_NPC_M_NULL`,text:{KOREA:`터트려!`,JPN:`爆破！`,ENG:`Blow it up!`,TWN:`引爆！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`GATE_NPC_CHARADE_NULL`,text:{KOREA:`바… 방벽? 저건 무슨 형태의 침식체인 거지?`,JPN:`ぼ……防壁？　あれはどういう形の侵食体なんだ？`,ENG:`A... A barrier? What type of C.O. is that?`,TWN:`屏……屏障？那是什麼侵蝕體？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:null,R:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`COUNTER_NPC_M_NULL`,text:{KOREA:`제길…! 폭발이 막혔어! 놈들이 온다!`,JPN:`くそ……！　爆発失敗！　奴らが来るぞ！`,ENG:`Dammit...! The explosion didn't go through! They're coming!`,TWN:`該死……！爆炸被擋下了！他們要來了！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`GATE_NPC_CHARADE_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_NULL`,text:{KOREA:`증원 도착했습니다.`,JPN:`増援、到着しました。`,ENG:`Backup is here.`,TWN:`增援人力已經抵達。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`PIONE_ZODIAC_NULL_NULL`,text:{KOREA:`다행히 늦진 않았군요.`,JPN:`間に合ったようですね。`,ENG:`Luckily, we're not too late.`,TWN:`幸好沒有來遲。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`PIONE_ZODIAC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`COUNTER_NPC_M_NULL`,text:{KOREA:`당신들은…? 건틀렛에 출전했던 기사단?`,JPN:`あんたらは……？　ガントレットに出戦した騎士団か？`,ENG:`You're... the order who participated in Gauntlet?`,TWN:`你們是……？出戰過聖鎧的騎士團？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`COUNTER_NPC_M_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`YANGHANSOL_ZODIAC_NULL_NULL`,text:{KOREA:`적이 엄청 많네요. 하지만 기사단의 긍지를 위해 맞서겠습니다!`,JPN:`敵が多いですね。でも、騎士団の誇りのため立ち向かいます！`,ENG:`There are a lot of enemies. But we'll fight them, for the honor of the Knights!`,TWN:`敵人數量好驚人。但為了騎士團的榮譽，我們會奮戰到底！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`YANGHANSOL_ZODIAC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};